import { SignInUsername } from "./username/sign-in-username"

export function SignIn() {
  return <SignInUsername />
}

import { authQueryKeys } from "@better-auth-ui/core"
import {
  type UsernameLocalization,
  usernameLocalization
} from "@better-auth-ui/core/plugins"
import {
  signInEmailOptions,
  signInUsernameOptions,
  type UsernameAuthClient,
  useAuth
} from "@better-auth-ui/solid"
import { createMutation, useQueryClient } from "@tanstack/solid-query"
import { Link } from "@tanstack/solid-router"
import { Eye, EyeOff } from "lucide-solid"
import { type Component, createSignal, For, Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { ProviderButtons } from "../provider-buttons"
import { resolveSubmittedSignIn } from "../sign-in-path"

export type SignInUsernameProps = {
  className?: string
}

type AuthButtonComponent = Component<{ view?: string }>

type AuthPluginWithButtons = {
  authButtons?: AuthButtonComponent[]
  id: string
}

export function SignInUsername(props: SignInUsernameProps) {
  const auth = useAuth()
  const queryClient = useQueryClient()
  const [identifier, setIdentifier] = createSignal("")
  const [identifierError, setIdentifierError] = createSignal<string>()
  const [password, setPassword] = createSignal("")
  const [passwordError, setPasswordError] = createSignal<string>()
  const [isPasswordVisible, setIsPasswordVisible] = createSignal(false)
  const onSignInSuccess = () => {
    queryClient.invalidateQueries({ queryKey: authQueryKeys.session })
    auth.navigate({ to: auth.redirectTo })
  }
  const signIn = createMutation(() => ({
    ...signInEmailOptions(auth.authClient),
    onSuccess: onSignInSuccess
  }))
  const signInUsername = createMutation(() => ({
    ...signInUsernameOptions(auth.authClient as UsernameAuthClient),
    onSuccess: onSignInSuccess
  }))
  const usernamePlugin = auth.plugins.find((plugin) => plugin.id === "username")
  const usernameAuth = Boolean(usernamePlugin)
  const usernameLabels: UsernameLocalization = {
    ...usernameLocalization,
    ...(usernamePlugin?.localization as
      | Partial<UsernameLocalization>
      | undefined)
  }

  const submitSignIn = (
    event: SubmitEvent & { currentTarget: HTMLFormElement }
  ) => {
    event.preventDefault()

    const { password: submittedPassword, signInPath } = resolveSubmittedSignIn({
      formData: new FormData(event.currentTarget),
      usernameAuth
    })

    setIdentifier(
      signInPath.kind === "username" ? signInPath.username : signInPath.email
    )
    setPassword(submittedPassword)

    if (signInPath.kind === "username") {
      signInUsername.mutate({
        password: submittedPassword,
        username: signInPath.username
      })
      return
    }

    signIn.mutate({
      email: signInPath.email,
      password: submittedPassword
    })
  }

  return (
    <Card class={props.className ?? "w-full max-w-sm"}>
      <CardHeader>
        <CardTitle class="text-xl font-semibold">
          {auth.localization.auth.signIn}
        </CardTitle>
      </CardHeader>

      <CardContent>
        <form aria-label="Sign in" onSubmit={submitSignIn}>
          <div class="flex flex-col gap-6">
            <div class="grid gap-3">
              <Label for="sign-in-email">
                {usernameAuth
                  ? usernameLabels.username
                  : auth.localization.auth.email}
              </Label>
              <Input
                aria-invalid={Boolean(identifierError())}
                autocomplete={usernameAuth ? "username" : "email"}
                id="sign-in-email"
                name={usernameAuth ? "username" : "email"}
                onInput={(event) => {
                  setIdentifier(event.currentTarget.value)
                  setIdentifierError(undefined)
                }}
                onInvalid={(event) => {
                  event.preventDefault()
                  setIdentifierError(event.currentTarget.validationMessage)
                }}
                placeholder={
                  usernameAuth
                    ? usernameLabels.usernameOrEmailPlaceholder
                    : auth.localization.auth.emailPlaceholder
                }
                required
                type={usernameAuth ? "text" : "email"}
                value={identifier()}
              />

              <Show when={identifierError()}>
                {(message) => (
                  <p class="text-sm text-destructive" role="alert">
                    {message()}
                  </p>
                )}
              </Show>
            </div>

            <div class="grid gap-3">
              <Label for="sign-in-password">
                {auth.localization.auth.password}
              </Label>
              <div class="relative">
                <Input
                  aria-invalid={Boolean(passwordError())}
                  autocomplete="current-password"
                  class="pr-12"
                  id="sign-in-password"
                  maxLength={auth.emailAndPassword.maxPasswordLength}
                  minLength={auth.emailAndPassword.minPasswordLength}
                  name="password"
                  onInput={(event) => {
                    setPassword(event.currentTarget.value)
                    setPasswordError(undefined)
                  }}
                  onInvalid={(event) => {
                    event.preventDefault()
                    setPasswordError(event.currentTarget.validationMessage)
                  }}
                  placeholder={auth.localization.auth.passwordPlaceholder}
                  required
                  type={isPasswordVisible() ? "text" : "password"}
                  value={password()}
                />

                <Button
                  aria-label={
                    isPasswordVisible()
                      ? auth.localization.auth.hidePassword
                      : auth.localization.auth.showPassword
                  }
                  class="absolute right-1 top-1/2 -translate-y-1/2"
                  onClick={() => setIsPasswordVisible((visible) => !visible)}
                  size="icon-sm"
                  title={
                    isPasswordVisible()
                      ? auth.localization.auth.hidePassword
                      : auth.localization.auth.showPassword
                  }
                  type="button"
                  variant="ghost"
                >
                  {isPasswordVisible() ? (
                    <EyeOff aria-hidden class="size-4" />
                  ) : (
                    <Eye aria-hidden class="size-4" />
                  )}
                </Button>
              </div>

              <Show when={passwordError()}>
                {(message) => (
                  <p class="text-sm text-destructive" role="alert">
                    {message()}
                  </p>
                )}
              </Show>
            </div>

            <Button
              disabled={signIn.isPending || signInUsername.isPending}
              type="submit"
            >
              {signIn.isPending || signInUsername.isPending
                ? `${auth.localization.auth.signIn}…`
                : auth.localization.auth.signIn}
            </Button>

            <For
              each={(auth.plugins as AuthPluginWithButtons[]).flatMap(
                (plugin) =>
                  (plugin.authButtons ?? []).map((AuthButton, index) => ({
                    AuthButton,
                    key: `${plugin.id}-${index.toString()}`
                  }))
              )}
            >
              {({ AuthButton }) => <AuthButton view="signIn" />}
            </For>

            <Show when={signIn.isError || signInUsername.isError}>
              <p role="alert">Unable to sign in. Try again.</p>
            </Show>
          </div>
        </form>

        <Show when={auth.socialProviders?.length}>
          <div class="my-4 text-center text-muted-foreground text-xs">
            {auth.localization.auth.or}
          </div>
          <ProviderButtons view="signIn" />
        </Show>

        <div class="mt-4 flex w-full flex-col items-center gap-3">
          <Show when={auth.emailAndPassword.forgotPassword}>
            <Link
              class="text-sm underline-offset-4 hover:underline"
              params={{ path: auth.viewPaths.auth.forgotPassword }}
              to="/auth/$path"
            >
              {auth.localization.auth.forgotPasswordLink}
            </Link>
          </Show>

          <p class="text-center text-sm text-muted-foreground">
            {auth.localization.auth.needToCreateAnAccount}{" "}
            <Link
              class="underline underline-offset-4"
              params={{ path: auth.viewPaths.auth.signUp }}
              to="/auth/$path"
            >
              {auth.localization.auth.signUp}
            </Link>
          </p>
        </div>
      </CardContent>
    </Card>
  )
}

import type { SocialProvider } from "better-auth/social-providers"

const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/

export type SignInPathInput = {
  identifier: string
  usernameAuth: boolean
}

export type SignInPath =
  | { kind: "email"; email: string }
  | { kind: "username"; username: string }

export type SubmittedSignInInput = {
  formData: FormData
  usernameAuth: boolean
}

export type SubmittedSignIn = {
  password: string
  signInPath: SignInPath
}

export type SocialAuthView = "signIn" | "signUp"

export type SocialAuthURLInput = {
  basePaths: { auth: string }
  baseURL: string
  redirectTo: string
  view: SocialAuthView
  viewPaths: { auth: { signIn: string; signUp: string } }
}

export type SocialAuthURLs = {
  callbackURL: string
  errorCallbackURL: string
  newUserCallbackURL?: string
}

export type SocialAuthParamsInput = SocialAuthURLInput & {
  provider: SocialProvider
}

export type SocialAuthParams = SocialAuthURLs & {
  provider: SocialProvider
}

const getFormValue = (formData: FormData, name: string) => {
  const value = formData.get(name)

  return typeof value === "string" ? value : ""
}

export function resolveSignInPath({
  identifier,
  usernameAuth
}: SignInPathInput): SignInPath {
  const normalizedIdentifier = identifier.trim()

  if (usernameAuth && !emailPattern.test(normalizedIdentifier)) {
    return { kind: "username", username: normalizedIdentifier }
  }

  return { kind: "email", email: normalizedIdentifier }
}

export function resolveSubmittedSignIn({
  formData,
  usernameAuth
}: SubmittedSignInInput): SubmittedSignIn {
  const identifier = usernameAuth
    ? getFormValue(formData, "username")
    : getFormValue(formData, "email")

  return {
    password: getFormValue(formData, "password"),
    signInPath: resolveSignInPath({ identifier, usernameAuth })
  }
}

export function resolveSocialAuthURLs({
  basePaths,
  baseURL,
  redirectTo,
  view,
  viewPaths
}: SocialAuthURLInput): SocialAuthURLs {
  const authViewPath =
    view === "signUp" ? viewPaths.auth.signUp : viewPaths.auth.signIn
  const urls: SocialAuthURLs = {
    callbackURL: `${baseURL}${redirectTo}`,
    errorCallbackURL: `${baseURL}${basePaths.auth}/${authViewPath}`
  }

  if (view === "signUp") {
    urls.newUserCallbackURL = `${baseURL}${redirectTo}`
  }

  return urls
}

export function resolveSocialAuthParams({
  provider,
  ...input
}: SocialAuthParamsInput): SocialAuthParams {
  return {
    provider,
    ...resolveSocialAuthURLs(input)
  }
}

import { getProviderName } from "@better-auth-ui/core"
import { useAuth } from "@better-auth-ui/solid"
import type { SocialProvider } from "better-auth/social-providers"
import type { ComponentProps } from "solid-js"
import { createSignal } from "solid-js"
import { Button } from "@/components/ui/button"
import { resolveSocialAuthParams, type SocialAuthView } from "./sign-in-path"

export type ProviderButtonProps = {
  display?: "full" | "icon" | "name"
  provider: SocialProvider
  view?: SocialAuthView
} & Omit<ComponentProps<typeof Button>, "children" | "disabled" | "onClick">

export function ProviderButton(props: ProviderButtonProps) {
  const auth = useAuth()
  const [isPending, setIsPending] = createSignal(false)
  const display = () => props.display ?? "full"
  const providerName = () => getProviderName(props.provider)
  const label = () =>
    auth.localization.auth.continueWith.replace("{{provider}}", providerName())
  const signInSocial = async () => {
    if (isPending()) return

    setIsPending(true)

    try {
      await auth.authClient.signIn.social(
        resolveSocialAuthParams({
          provider: props.provider,
          basePaths: auth.basePaths,
          baseURL: auth.baseURL,
          redirectTo: auth.redirectTo,
          view: props.view ?? "signIn",
          viewPaths: auth.viewPaths
        }) as Parameters<typeof auth.authClient.signIn.social>[0]
      )
    } finally {
      setIsPending(false)
    }
  }

  return (
    <Button
      aria-label={providerName()}
      class={props.class}
      disabled={isPending()}
      onClick={signInSocial}
      type="button"
      variant={props.variant ?? "outline"}
    >
      <span aria-hidden>{providerName().slice(0, 1)}</span>
      {isPending()
        ? `${providerName()}…`
        : display() === "full"
          ? label()
          : display() === "name"
            ? providerName()
            : null}
    </Button>
  )
}

import { useAuth } from "@better-auth-ui/solid"
import { For } from "solid-js"
import { cn } from "@/lib/utils"
import { ProviderButton } from "./provider-button"
import type { SocialAuthView } from "./sign-in-path"

export type SocialLayout = "auto" | "grid" | "horizontal" | "vertical"

export type ProviderButtonsProps = {
  socialLayout?: SocialLayout
  view?: SocialAuthView
}

export function ProviderButtons(props: ProviderButtonsProps) {
  const auth = useAuth()
  const resolvedSocialLayout = () => {
    const socialLayout = props.socialLayout ?? "auto"
    if (socialLayout !== "auto") return socialLayout

    return auth.socialProviders?.length && auth.socialProviders.length >= 4
      ? "horizontal"
      : "vertical"
  }

  return (
    <div
      class={cn(
        "gap-3",
        resolvedSocialLayout() === "grid" && "grid grid-cols-2",
        resolvedSocialLayout() === "vertical" && "flex flex-col",
        resolvedSocialLayout() === "horizontal" && "flex flex-row flex-wrap"
      )}
    >
      <For each={auth.socialProviders ?? []}>
        {(provider) => (
          <ProviderButton
            class={cn(resolvedSocialLayout() === "horizontal" && "flex-1")}
            display={
              resolvedSocialLayout() === "vertical"
                ? "full"
                : resolvedSocialLayout() === "grid"
                  ? "name"
                  : "icon"
            }
            provider={provider}
            view={props.view}
          />
        )}
      </For>
    </div>
  )
}

import { type ButtonRootProps, Root } from "@kobalte/core/button"
import type { PolymorphicProps } from "@kobalte/core/polymorphic"
import { cva, type VariantProps } from "class-variance-authority"
import { type ComponentProps, splitProps, type ValidComponent } from "solid-js"
import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "group/button z-button inline-flex shrink-0 select-none items-center justify-center whitespace-nowrap outline-none transition-all active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "z-button-variant-default",
        outline: "z-button-variant-outline",
        secondary: "z-button-variant-secondary",
        ghost: "z-button-variant-ghost",
        destructive: "z-button-variant-destructive",
        link: "z-button-variant-link"
      },
      size: {
        default: "z-button-size-default",
        xs: "z-button-size-xs",
        sm: "z-button-size-sm",
        lg: "z-button-size-lg",
        icon: "z-button-size-icon",
        "icon-xs": "z-button-size-icon-xs",
        "icon-sm": "z-button-size-icon-sm",
        "icon-lg": "z-button-size-icon-lg"
      }
    },
    defaultVariants: {
      variant: "default",
      size: "default"
    }
  }
)

type ButtonProps<T extends ValidComponent = "button"> = PolymorphicProps<
  T,
  ButtonRootProps<T>
> &
  VariantProps<typeof buttonVariants> &
  Pick<ComponentProps<T>, "class">

const Button = <T extends ValidComponent = "button">(props: ButtonProps<T>) => {
  const [local, others] = splitProps(props as ButtonProps, [
    "variant",
    "size",
    "class"
  ])

  return (
    <Root
      class={cn(
        buttonVariants({ variant: local.variant, size: local.size }),
        local.class
      )}
      data-slot="button"
      {...others}
    />
  )
}

export { Button, type ButtonProps, buttonVariants }

